public void init()
{
    super();

    Args args = element.args();
    PurchTable purchTableArg;
    PurchTable purchTable;
    VendTable  vendTable;
    PurchAgreementHeader purchAHeader;
    InventTable inventTable;
    DimensionDefault     defaultDimRecId;
    Currency currency;
    ETGCanadaParameters canadaParameters = ETGCanadaParameters::find();

    if (args && args.record() && args.record().TableId == tableNum(PurchTable))
    {
        purchTableArg = args.record();
        purchTable    = PurchTable::find(purchTableArg.PurchId, true);


        ETGGrainReceiptNoteTable_ds.create(true);
        ETGGrainReceiptNoteTable header = ETGGrainReceiptNoteTable_ds.cursor();

        header.PurchId           = purchTable.PurchId;
        header.VendAccount       = purchTable.OrderAccount;

        header.ElevatorReceiptId = purchTable.ETGElevatorReceiptNumber;

        currency = Currency::find(purchTable.CurrencyCode);

        header.CurrencyCode = currency.Symbol;

        // Vendor info
        vendTable = VendTable::find(purchTable.OrderAccount);
        if (vendTable)
        {
            header.ProducerName    = vendTable.customerAccountName();
            header.ProducerAddress = vendTable.postalAddress().Address;
        }

        purchAHeader = PurchAgreementHeader::find(purchTable.MatchingAgreement);
        if (purchAHeader)
        {
            header.ContractNumber = purchAHeader.PurchNumberSequence;
        }

        delete_from ETGGrainReceiptNoteLine
        where ETGGrainReceiptNoteLine.GrainReceiptNoteId == header.GrainReceiptNoteId;

        PurchLine purchLine, purchLineDim;
        ETGGrainReceiptNoteLine grnLine;
        int grnLineNo = 1;
        real total = 0.00;
        real chargesTotal = 0.0;
        while select purchLine
        where purchLine.PurchId == purchTable.PurchId
           && purchLine.PurchStatus != PurchStatus::Canceled
        {
            grnLine.clear();
            grnLine.initValue();

            grnLine.GrainReceiptNoteId = header.GrainReceiptNoteId;
            grnLine.LineNumber         = grnLineNo;
            grnLine.ItemId             = purchLine.ItemId;
            grnLine.Description        = purchLine.itemName();
            grnLine.Qty                = purchLine.RemainPurchPhysical;  
            grnLine.Price              = purchLine.PurchPrice;
            grnLine.LineAmount         = grnLine.Qty * grnLine.Price;
            total                     += grnLine.LineAmount;

            grnLine.insert();
            grnLineNo++;
        }


        header.calculateTotals();
        header.recalcNetAmountPayable();

        ETGGrainReceiptNoteLine_ds.executeQuery();
        ETGGrainReceiptNoteTable_ds.refresh();
    }
}

/// <summary>
///
/// </summary>
/// <returns></returns>
public int active()
{
    int ret;
    ret = super();

    ETGGrainReceiptNoteTable head = ETGGrainReceiptNoteTable;

    boolean isDraft     = head.GrainReceiptStatus == ETGGrainReceiptStatus::Draft;
    boolean isConfirmed = head.GrainReceiptStatus == ETGGrainReceiptStatus::Confirmed;

    ETGGrainReceiptNoteTable_ds.allowEdit(isDraft);
    ETGGrainReceiptNoteLine_ds.allowEdit(isDraft);
    ETGGrainReceiptCharges_ds.allowEdit(isDraft);
    ETGGrainReceiptPaymentTable_ds.allowEdit(isDraft);
    AddButton.enabled(isDraft);
    Remove.enabled(isDraft);

    SubmitButton.enabled(isDraft);
    PrintGrainReceipt.enabled(isConfirmed);

    ChangeRequest.enabled(isConfirmed);

    ETGGrainReceiptNoteTable header = this.cursor();
    ETGElevatorReceiptTable elevatorReceipt;
    InventTable inventTable;
    ETGScaleTicketTable scaleTicket;
    ETGElevatorReceiptGrainItemTable grainItem;
    PurchTable purchTable = PurchTable::find(header.PurchId);
    PurchLine purchLine;
    ETGCanadaParameters canadaParameters = ETGCanadaParameters::find();

    AutoPostGRN.enabled(isConfirmed && purchTable.PurchStatus == PurchStatus::Backorder);

    select purchLine
    where purchLine.PurchId == purchTable.PurchId
        && purchLine.PurchStatus != PurchStatus::Canceled;

    if (header && header.ElevatorReceiptId)
    {
        select firstonly crossCompany elevatorReceipt
        where elevatorReceipt.ElevatorReceiptNumber == header.ElevatorReceiptId;

        if (elevatorReceipt)
        {
            header.ProductionEntity        = elevatorReceipt.DataAreaId;
            header.GrossWeight             = elevatorReceipt.GrossWeight;
            header.VehicleWeight           = elevatorReceipt.VehicleWeight;
            header.ProductUnloaded         = elevatorReceipt.GrainUnloadedWeight;
            header.ScaleTicketNumber       = elevatorReceipt.ScaleTicketReferenceNumber;
            header.StationName             = elevatorReceipt.StationName;
            header.DockagePercentage       = elevatorReceipt.DockagePercentage;
            header.SplitsPercentage        = elevatorReceipt.SplitsPercentage;
            header.DockageWeight           = elevatorReceipt.DockageWeight;
            header.SplitsWeight            = elevatorReceipt.SplitsWeight;
            header.FinalMainProductWeight  =  (header.ProductUnloaded - (header.DockageWeight +  header.SplitsWeight));
            header.NetWeight               = (elevatorReceipt.GrainUnloadedWeight - elevatorReceipt.DockageWeight - elevatorReceipt.SplitsWeight);
            header.FinalMainProductWeight  =  (elevatorReceipt.GrainUnloadedWeight - elevatorReceipt.DockageWeight - elevatorReceipt.SplitsWeight);
            header.CropYearCopy            =  ETGFixedAssetFinancialsDimensions::getDimensionDisplayValueCodeOnlyETG(purchLine.DefaultDimension,canadaParameters.CropYear);


            if(header.ProductionEntity == 'p012')
            {
            header.ProductionEntity  =  "P012";
            }
            else if(header.ProductionEntity == 'p009')
            {
                header.ProductionEntity  =  "P009";
            }
            else
            {
                header.ProductionEntity  =  header.ProductionEntity;
            }

            select firstonly crossCompany grainItem
                where grainItem.ElevatorReceiptNumber == elevatorReceipt.ElevatorReceiptNumber;

            if(grainItem)
            {
                select firstonly crossCompany inventTable
                where inventTable.ItemId == grainItem.ItemId;

                if (inventTable)
                {
                    header.Commodity = inventTable.ETGCommodity;
                }
            }

            if( header.ScaleTicketNumber)
            {
                select firstonly crossCompany scaleTicket
                where scaleTicket.ScaleTicketNumber == header.ScaleTicketNumber;

                if(scaleTicket)
                {
                    header.ContractNumber = scaleTicket.RefPurchAgreementNum;
                }
            }

            ttsbegin;
            header.update();
            ttscommit;

            ETGGrainReceiptNoteTable_ds.reread();
            ETGGrainReceiptNoteTable_ds.refresh();
        }
    }

    return ret;
}

/// <summary>
/// For number sequence
/// </summary>
public void initValue()
{
    super();
    ttsbegin;
    ETGGrainReceiptNoteTable.GrainReceiptNoteId =
    NumberSeq::newGetNum(NumberSeqReference::findReference(extendedTypeNum(ETGGrainReceiptNoteId))).num();
    ttscommit;
}

/// <summary>
/// This method is for Submit button clicked
/// </summary>
public void clicked()
{
    ETGGrainReceiptNoteTable header = ETGGrainReceiptNoteTable_ds.cursor();

    if (!header)
    return;

    ETGGrainReceiptPaymentTable pay;
    real totalPct = 0.00;

    while select pay
    where pay.GrainReceiptNoteId == header.GrainReceiptNoteId
    {
        totalPct += pay.Percentage;
    }

    if (round(totalPct, 2) != 100)
    {
        throw error(strFmt(
        "Total payment percentage must be 100. Current total is %1.",
        totalPct));
    }

    ttsbegin;
    header = ETGGrainReceiptNoteTable::findFromGrainReceiptNote(header.GrainReceiptNoteId,true);
    ETGGrainReceiptNoteTable.GrainReceiptStatus = ETGGrainReceiptStatus::Confirmed;
    ETGGrainReceiptNoteTable.update();
    ttscommit;

    ETGGrainReceiptNoteTable_ds.research(true);
    ETGGrainReceiptNoteTable_ds.refresh();
}

