/// <summary>
/// This method is for capturing grain receipt number for print
/// </summary>
public void clicked()
{
    Args args = new Args();
    args.record(ETGGrainReceiptNoteTable);
    args.menuItemName(menuItemOutputStr(ETGGrainReceiptPrint));

    new MenuFunction(menuItemOutputStr(ETGGrainReceiptPrint), MenuItemType::Output).run(args);
}

public void clicked()
{

    ETGGrainReceiptNoteTable header = ETGGrainReceiptNoteTable_ds.cursor();
    PurchTable purchTable;
    PurchFormLetter_PackingSlip purchFormLetter;

    if (!header)
    return;

    if (header.GrainReceiptStatus != ETGGrainReceiptStatus::Confirmed)
    {
        warning("GRN must be confirmed before posting.");
        return;
    }

    if (header.IsPosted == NoYes::Yes)
    {
        warning("This GRN is already posted.");
        return;
    }

    purchTable = PurchTable::find(header.PurchId, true);

    if (!purchTable)
    throw error("Purchase order not found.");

    ttsbegin;

    InventTransWMS_Register     inventTransWMS_register;
    TmpInventTransWMS           tmpInventTransWMS;

    PurchLine PurchLine;

    while select PurchLine
        where PurchLine.PurchId == purchTable.PurchId
    {
        InventDim               inventDim,inventBatchCheck,inventDimlocal;

        InventTrans             inventTranslocal;

        inventDim                           =  InventDim::find(PurchLine.InventDimId);

        inventTranslocal = InventTrans::findTransId(PurchLine.InventTransId, true);
        inventDimlocal   = inventTranslocal.inventDim();

        inventDimlocal.inventBatchId    = inventDim.inventBatchId;
        inventDimlocal.InventLocationId = inventDim.InventLocationId;
        inventDimlocal.InventSiteId     = inventDim.inventSiteId;
        inventDimlocal.inventSerialId   = inventDim.inventSerialId;
        inventDimlocal.wMSLocationId    = inventDim.wMSLocationId;
        inventDimlocal                  = InventDim::findOrCreate(inventDimlocal);
        inventTransWMS_register         = inventTransWMS_register::newStandard(tmpInventTransWMS);

        inventTranslocal.inventDimId    = inventDimlocal.inventDimId;

        tmpInventTransWMS.clear();
        tmpInventTransWMS.initFromInventTrans(inventTranslocal);
        tmpInventTransWMS.ItemId    = inventTranslocal.ItemId;
        tmpInventTransWMS.InventQty = PurchLine.PurchQty;
        tmpInventTransWMS.insert();

        inventTransWMS_register.writeTmpInventTransWMS(tmpInventTransWMS, inventTranslocal, inventDimlocal);

        inventTransWMS_register.updateInvent(inventTranslocal);
    }

    VendPackingSlipJour VendPackingSlipJour;
    Str1260 PackingSlipNumber;

    select count(RecId) from VendPackingSlipJour
        where VendPackingSlipJour.PurchId == purchTable.PurchId;

    int counter = VendPackingSlipJour.RecId + 1;
    PackingSlipNumber = header.GrainReceiptNoteId + ' - ' + int2Str(counter);

    purchFormLetter = PurchFormLetter::construct(DocumentStatus::PackingSlip);

    purchFormLetter.update(purchTable,
        PackingSlipNumber,
        systemDateGet(),
        PurchUpdate::All,
        AccountOrder::None,
        false,
        false);

    ttscommit;
    purchTable.reread();

    if (purchTable.PurchStatus == PurchStatus::Received)
    {
        info("Product receipt posted successfully.");
    }
    else
    {
        warning("No quantity was posted.");
    }
}

